public class BankTransaction {

    static double balance = 500.0;

    static void withdraw(double amount) {
        if (amount > balance) {
            throw new IllegalArgumentException("Insufficient funds. Balance: " + balance);
        }
        balance -= amount;
        System.out.println("Withdrawn: " + amount + " | New balance: " + balance);
    }

    public static void main(String[] args) {
        // Attempt 1: valid withdrawal of 200
        try {
            withdraw(200);
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        } finally {
            System.out.println("Transaction 1 complete.");
        }

        // Attempt 2: invalid withdrawal of 400 (only 300 left)
        try {
            withdraw(400);
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        } finally {
            System.out.println("Transaction 2 complete.");
        }
    }
}

// Define custom exception class below
class InvalidAgeException extends Exception {
    // Constructor: accepts a String message and passes to super()
}

public class VoterRegistration {

    static void registerVoter(String name, int age) throws InvalidAgeException {
        if (age < 18) {
            throw new InvalidAgeException(name + " is too young to vote. Age: " + age);
        }
        System.out.println(name + " registered successfully. Age: " + age);
    }

    public static void main(String[] args) {
        String[][] candidates = {{"Alice", "25"}, {"Tom", "16"}, {"Carol", "19"}};

        for (String[] c : candidates) {
            try {
                registerVoter(c[0], Integer.parseInt(c[1]));
            } catch (InvalidAgeException e) {
                System.out.println("Registration failed: " + e.getMessage());
            }
        }
    }
}

public class MultiCatch {

    static void riskyOperation(int[] arr, int index, int divisor) {
        try {
            int value = arr[index];         // may throw ArrayIndexOutOfBoundsException
            int result = value / divisor;   // may throw ArithmeticException
            System.out.println("Result: " + result);
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("Array error: " + e.getMessage());
        } catch (ArithmeticException e) {
            System.out.println("Math error: " + e.getMessage());
        } finally {
            System.out.println("---");
        }
    }

    public static void main(String[] args) {
        int[] data = {10, 20, 30};

        riskyOperation(data, 1, 4);   // normal: 20 / 4 = 5
        riskyOperation(data, 5, 4);   // bad index
        riskyOperation(data, 0, 0);   // divide by zero
    }
}
